"use client";

import { useMemo } from "react";
import { PurchaseOrder } from "@/types";
import { formatCurrency } from "@/lib/currencies";

interface PODetailModalProps {
    po: PurchaseOrder;
    onClose: () => void;
    onReceive: (id: string, poNumber: string) => void;
    onEmailVendor?: (po: PurchaseOrder) => void;
}

export default function PODetailModal({
    po,
    onClose,
    onReceive,
    onEmailVendor
}: PODetailModalProps) {

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 50,
            backgroundColor: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem'
        }} className="modal-backdrop">
            <style>{`
                @media print {
                    @page { margin: 0; }
                    body * { visibility: hidden; }
                    .print-container, .print-container * { visibility: visible; }
                    .print-container {
                        position: absolute !important;
                        left: 0 !important;
                        top: 0 !important;
                        width: 100% !important;
                        height: auto !important;
                        padding: 2rem !important;
                        margin: 0 !important;
                        box-shadow: none !important;
                        background: white !important;
                    }
                    .no-print { display: none !important; }
                    .modal-backdrop { 
                        position: static !important;
                        display: block !important;
                        background: none !important;
                        backdrop-filter: none !important;
                        padding: 0 !important;
                    }
                }
            `}</style>
            {/* Main Container - Split View */}
            <div style={{ display: 'flex', gap: '2rem', height: '100%', maxHeight: '900px', width: '1200px' }}>

                {/* Left: Document Preview (A4 Paper Ratio) */}
                <div style={{
                    flex: '1', backgroundColor: 'white', borderRadius: '4px',
                    boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
                    overflowY: 'auto', padding: '3rem', position: 'relative',
                    fontFamily: 'Times New Roman, serif' // Simulate official document
                }} className="print-container">

                    {/* Watermark for status */}
                    <div style={{
                        position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%) rotate(-45deg)',
                        fontSize: '6rem', fontWeight: 'bold', color: po.status === 'ISSUED' ? '#eff6ff' : po.status === 'RECEIVED' ? '#ecfdf5' : '#f3f4f6',
                        zIndex: 0, pointerEvents: 'none', border: `8px solid ${po.status === 'ISSUED' ? '#dbeafe' : po.status === 'RECEIVED' ? '#d1fae5' : '#e5e7eb'}`,
                        padding: '1rem 4rem', opacity: 0.5
                    }}>
                        {po.status}
                    </div>

                    <div style={{ position: 'relative', zIndex: 1 }}>
                        {/* Header */}
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3rem' }}>
                            <div>
                                <h1 style={{ fontSize: '2rem', fontWeight: 'bold', color: '#111827', marginBottom: '0.5rem', fontFamily: 'Arial, sans-serif' }}>PURCHASE ORDER</h1>
                                <div style={{ fontSize: '0.9rem', color: '#4b5563' }}>PO Number: <strong>{po.poNumber}</strong></div>
                                <div style={{ fontSize: '0.9rem', color: '#4b5563' }}>Date: {po.issuedAt.toLocaleDateString()}</div>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '1.2rem', marginBottom: '0.25rem' }}>Acme Corp Inc.</div>
                                <div style={{ fontSize: '0.9rem', color: '#6b7280' }}>123 Enterprise Blvd</div>
                                <div style={{ fontSize: '0.9rem', color: '#6b7280' }}>Tech City, TC 94043</div>
                            </div>
                        </div>

                        {/* Vendor & Ship To */}
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3rem', gap: '2rem' }}>
                            <div style={{ flex: 1, border: '1px solid #e5e7eb', padding: '1rem' }}>
                                <h3 style={{ fontSize: '0.9rem', fontWeight: 'bold', color: '#374151', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Vendor</h3>
                                <div style={{ fontWeight: 'bold' }}>{po.vendorName}</div>
                                <div>Attn: Sales Dept</div>
                                <div>vendor@example.com</div>
                            </div>
                            <div style={{ flex: 1, border: '1px solid #e5e7eb', padding: '1rem' }}>
                                <h3 style={{ fontSize: '0.9rem', fontWeight: 'bold', color: '#374151', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Ship To</h3>
                                <div style={{ fontWeight: 'bold' }}>Acme Corp Warehouse</div>
                                <div>Receiving Dock B</div>
                                <div>123 Enterprise Blvd, Tech City</div>
                            </div>
                        </div>

                        {/* Items Table */}
                        <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '2rem' }}>
                            <thead>
                                <tr style={{ backgroundColor: '#111827', color: 'white' }}>
                                    <th style={{ padding: '0.75rem', textAlign: 'left', fontSize: '0.9rem', fontFamily: 'Arial, sans-serif' }}>Description</th>
                                    <th style={{ padding: '0.75rem', textAlign: 'center', fontSize: '0.9rem', fontFamily: 'Arial, sans-serif' }}>Quantity</th>
                                    <th style={{ padding: '0.75rem', textAlign: 'right', fontSize: '0.9rem', fontFamily: 'Arial, sans-serif' }}>Unit Price</th>
                                    <th style={{ padding: '0.75rem', textAlign: 'right', fontSize: '0.9rem', fontFamily: 'Arial, sans-serif' }}>Total</th>
                                </tr>
                            </thead>
                            <tbody>
                                {po.items.map((item, i) => (
                                    <tr key={i} style={{ borderBottom: '1px solid #e5e7eb' }}>
                                        <td style={{ padding: '0.75rem' }}>{item.description}</td>
                                        <td style={{ padding: '0.75rem', textAlign: 'center' }}>{item.quantity}</td>
                                        <td style={{ padding: '0.75rem', textAlign: 'right' }}>{formatCurrency(item.unitPrice, po.currency)}</td>
                                        <td style={{ padding: '0.75rem', textAlign: 'right' }}>{formatCurrency(item.total, po.currency)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>

                        {/* Totals */}
                        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '4rem' }}>
                            <div style={{ width: '250px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid #e5e7eb' }}>
                                    <span>Subtotal:</span>
                                    <span>{formatCurrency(po.totalAmount, po.currency)}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid #e5e7eb' }}>
                                    <span>Tax (0%):</span>
                                    <span>{formatCurrency(0, po.currency)}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', fontWeight: 'bold', fontSize: '1.2rem', marginTop: '0.5rem' }}>
                                    <span>Total:</span>
                                    <span>{formatCurrency(po.totalAmount, po.currency)}</span>
                                </div>
                            </div>
                        </div>

                        {/* Signature */}
                        <div style={{ display: 'flex', gap: '3rem', marginTop: 'auto' }}>
                            <div style={{ flex: 1 }}>
                                <div style={{ height: '1px', backgroundColor: 'black', marginBottom: '0.5rem' }}></div>
                                <div style={{ fontSize: '0.8rem' }}>Authorized Signature</div>
                            </div>
                            <div style={{ flex: 1 }}>
                                <div style={{ height: '1px', backgroundColor: 'black', marginBottom: '0.5rem' }}></div>
                                <div style={{ fontSize: '0.8rem' }}>Date</div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right: Actions Panel (App UI) */}
                <div style={{ width: '350px', display: 'flex', flexDirection: 'column', gap: '1rem' }} className="no-print">

                    <div className="card">
                        <h3 className="text-lg font-bold mb-4">Actions</h3>

                        <button
                            className="btn"
                            style={{ width: '100%', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                            onClick={() => window.print()}
                        >
                            🖨️ Print / Download PDF
                        </button>

                        <a
                            href={`mailto:vendor@example.com?subject=Purchase%20Order%20${po.poNumber}&body=Dear%20${po.vendorName},%0D%0A%0D%0APlease%20find%20attached%20Purchase%20Order%20${po.poNumber}%20for%20your%20review.%0D%0A%0D%0ATotal:%20${formatCurrency(po.totalAmount, po.currency)}%0D%0A%0D%0AThank%20you,%0D%0AAcme%20Corp`}
                            className="btn"
                            style={{
                                width: '100%', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
                                textDecoration: 'none', color: 'var(--text-primary)', backgroundColor: '#fff', border: '1px solid var(--border)'
                            }}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            📧 Email to Vendor
                        </a>
                    </div>

                    {po.status === 'ISSUED' && (
                        <div className="card" style={{ border: '2px solid var(--primary)' }}>
                            <h3 className="text-lg font-bold mb-2">Goods Receipt</h3>
                            <p className="text-sm text-gray-500 mb-4">
                                Confirm that the items have been delivered to the warehouse.
                            </p>
                            <button
                                className="btn btn-primary"
                                style={{ width: '100%' }}
                                onClick={() => onReceive(po.id!, po.poNumber)}
                            >
                                ✅ Mark as Received
                            </button>
                        </div>
                    )}

                    <div style={{ marginTop: 'auto' }}>
                        <button
                            onClick={onClose}
                            style={{
                                width: '100%', padding: '1rem',
                                backgroundColor: 'rgba(255,255,255,0.2)', color: 'white',
                                border: '1px solid rgba(255,255,255,0.4)', borderRadius: '8px',
                                cursor: 'pointer', fontWeight: 600
                            }}
                        >
                            Close Preview
                        </button>
                    </div>
                </div>

            </div>
        </div>
    );
}
